    pub fn get_account(&self, optional_args: &[Value]) -> Value {
        let mut params = get_arg(optional_args, 0, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        // get current or provided bitmax sub-account
        let mut account: Value = self.safe_value_k(params.clone(), "account", &[get_value(&self.options, &Value::Str("account".to_string()))]);
        let mut lowercaseAccount: Value = to_lower(&account);
        return self.capitalize(lowercaseAccount.clone());

    Value::Null
}

