/*
 * @method
 * @name ascendex#fetchMarkets
 * @description retrieves data on all markets for ascendex
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {object[]} an array of objects representing market data
 */
    pub async fn fetch_markets(&mut self, optional_args: &[Value]) -> Value {
        let mut params = get_arg(optional_args, 0, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        let mut spotPromise: Value = self.fetch_spot_markets(&[params.clone()]).await;
        let mut contractPromise: Value = self.fetch_contract_markets(&[params.clone()]).await;
        let mut spotMarketscontractMarketsVariable = promise_all(&Value::List(vec![spotPromise.clone(), contractPromise.clone()])).await;
        let mut spotMarkets: Value = get_value(&spotMarketscontractMarketsVariable, &Value::Int(0));
        let mut contractMarkets: Value = get_value(&spotMarketscontractMarketsVariable, &Value::Int(1));
        return self.array_concat(spotMarkets.clone(), contractMarkets.clone());

    Value::Null
}

