    pub fn parse_open_interest(&self, mut interest: Value, optional_args: &[Value]) -> Value {
        let mut market = get_arg(optional_args, 0, Value::Null);
        //
        // fetchOpenInterests
        //
        //    {
        //        time: '1772138885616',
        //        symbol: 'ZIL-PERP',
        //        markPrice: '0.004167783',
        //        indexPrice: '0.004168',
        //        lastPrice: '0.00416',
        //        openInterest: '7685003',
        //        fundingRate: '0.0003',
        //        nextFundingTime: '1772139600000'
        //    }
        //
        let mut marketId: Value = self.safe_string_k(interest.clone(), "symbol", &[]);
        let mut timestamp: Value = self.safe_integer_k(interest.clone(), "time", &[]);
        let mut openInterest: Value = self.safe_number_k(interest.clone(), "openInterest", &[]);
        return self.safe_open_interest(Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("info".to_string(), interest.clone());
        m.insert("symbol".to_string(), self.safe_symbol(marketId.clone(), &[market.clone(), Value::Null, Value::Str("swap".to_string())]));
        m.insert("baseVolume".to_string(), openInterest.clone());
        m.insert("quoteVolume".to_string(), Value::Null);
        m.insert("openInterestAmount".to_string(), openInterest.clone());
        m.insert("openInterestValue".to_string(), Value::Null);
        m.insert("timestamp".to_string(), timestamp.clone());
        m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
    m
}), &[market.clone()]);

    Value::Null
}

    pub fn parse_leverage(&self, mut leverage: Value, optional_args: &[Value]) -> Value {
        let mut market = get_arg(optional_args, 0, Value::Null);
        let mut marketId: Value = self.safe_string_k(leverage.clone(), "symbol", &[]);
        let mut leverageValue: Value = self.safe_integer_k(leverage.clone(), "leverage", &[]);
        let mut marginType: Value = self.safe_string_k(leverage.clone(), "marginType", &[]);
        let mut marginMode: Value = ternary(is_true(&(is_equal(&marginType, &Value::Str("crossed".to_string())))), Value::Str("cross".to_string()), Value::Str("isolated".to_string()));
        return Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("info".to_string(), leverage.clone());
        m.insert("symbol".to_string(), self.safe_symbol(marketId.clone(), &[market.clone()]));
        m.insert("marginMode".to_string(), marginMode.clone());
        m.insert("longLeverage".to_string(), leverageValue.clone());
        m.insert("shortLeverage".to_string(), leverageValue.clone());
    m
});

    Value::Null
}

    pub fn sign(&self, mut path: Value, optional_args: &[Value]) -> Value {
        let mut api = get_arg(optional_args, 0, Value::Str("public".to_string()));
        let mut method = get_arg(optional_args, 1, Value::Str("GET".to_string()));
        let mut params = get_arg(optional_args, 2, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        let mut headers = get_arg(optional_args, 3, Value::Null);
        let mut body = get_arg(optional_args, 4, Value::Null);
        let mut version: Value = get_value(&api, &Value::Int(0));
        let mut access: Value = get_value(&api, &Value::Int(1));
        let mut type_var: Value = self.safe_string(api.clone(), Value::Int(2), &[]);
        let mut url: Value = Value::Str("".to_string());
        let mut accountCategory: Value = Value::Bool(is_equal(&type_var, &Value::Str("accountCategory".to_string())));
        if is_true(&accountCategory) || is_true(&(is_equal(&type_var, &Value::Str("accountGroup".to_string())))) {
            url = add(&url, &self.implode_params(Value::Str("/{account-group}".to_string()), params.clone()));
            params = self.omit(params.clone(), Value::Str("account-group".to_string()), &[]);
        }
        let mut request: Value = self.implode_params(path.clone(), params.clone());
        url = add(&url, &Value::Str("/api/pro/".to_string()));
        if is_equal(&version, &Value::Str("v2".to_string())) {
            if is_equal(&type_var, &Value::Str("data".to_string())) {
                request = add(&add(&add(&Value::Str("data/".to_string()), &version), &Value::Str("/".to_string())), &request);
            }  else {
                request = add(&add(&version, &Value::Str("/".to_string())), &request);
            }
        }  else {
            url = add(&url, &add(&version, &Value::Str("/".to_string())));
        }
        if is_true(&accountCategory) {
            url = add(&url, &self.implode_params(Value::Str("{account-category}/".to_string()), params.clone()));
        }
        params = self.omit(params.clone(), Value::Str("account-category".to_string()), &[]);
        url = add(&url, &request);
        if is_true(&(is_equal(&version, &Value::Str("v1".to_string())))) && is_true(&(is_equal(&request, &Value::Str("cash/balance".to_string())))) || is_true(&(is_equal(&request, &Value::Str("margin/balance".to_string())))) {
            request = Value::Str("balance".to_string());
        }
        if is_true(&(is_equal(&version, &Value::Str("v1".to_string())))) && is_true(&(is_equal(&request, &Value::Str("spot/fee".to_string())))) {
            request = Value::Str("fee".to_string());
        }
        if is_greater_than_or_equal(&get_index_of(&request, &Value::Str("subuser".to_string())), &Value::Int(0)) {
            let mut parts: Value = split(&request, &Value::Str("/".to_string()));
            request = get_value(&parts, &Value::Int(2));
        }
        params = self.omit(params.clone(), self.extract_params(path.clone()), &[]);
        if is_equal(&access, &Value::Str("public".to_string())) {
            if is_true(&get_array_length(&object_keys(&params))) {
                url = add(&url, &add(&Value::Str("?".to_string()), &self.urlencode(params.clone(), &[])));
            }
        }  else {
            self.check_required_credentials(&[]);
            let mut timestamp: Value = to_string_val(&self.milliseconds());
            let mut payload: Value = add(&add(&timestamp, &Value::Str("+".to_string())), &request);
            let mut hmac: Value = self.hmac(self.encode(payload.clone()), self.encode(self.secret.clone()), Value::Str("sha256".to_string()), &[Value::Str("base64".to_string())]);
            headers = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("x-auth-key".to_string(), self.apiKey.clone());
                    m.insert("x-auth-timestamp".to_string(), timestamp.clone());
                    m.insert("x-auth-signature".to_string(), hmac.clone());
                m
            });
            if is_equal(&method, &Value::Str("GET".to_string())) {
                if is_true(&get_array_length(&object_keys(&params))) {
                    url = add(&url, &add(&Value::Str("?".to_string()), &self.urlencode(params.clone(), &[])));
                }
            }  else {
                add_element_to_object(&mut headers, &Value::Str("Content-Type".to_string()), Value::Str("application/json".to_string()));
                body = self.json(params.clone());
            }
        }
        url = add(&get_value(&get_value(&self.urls, &Value::Str("api".to_string())), &Value::Str("rest".to_string())), &url);
        return Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("url".to_string(), url.clone());
        m.insert("method".to_string(), method.clone());
        m.insert("body".to_string(), body.clone());
        m.insert("headers".to_string(), headers.clone());
    m
});

    Value::Null
}

    pub fn handle_errors(&self, mut httpCode: Value, mut reason: Value, mut url: Value, mut method: Value, mut headers: Value, mut body: Value, mut response: Value, mut requestHeaders: Value, mut requestBody: Value) -> Value {
        if is_equal(&response, &Value::Null) {
            return Value::Null;
        }
        //
        //     {"code": 6010, "message": "Not enough balance."}
        //     {"code": 60060, "message": "The order is already filled or canceled."}
        //     {"code":2100,"message":"ApiKeyFailure"}
        //     {"code":300001,"message":"Price is too low from market price.","reason":"INVALID_PRICE","accountId":"cshrHKLZCjlZ2ejqkmvIHHtPmLYqdnda","ac":"CASH","action":"place-order","status":"Err","info":{"symbol":"BTC/USDT"}}
        //
        let mut code: Value = self.safe_string_k(response.clone(), "code", &[]);
        let mut message: Value = self.safe_string_k(response.clone(), "message", &[]);
        let mut error: Value = Value::Bool(is_true(&(!is_equal(&code, &Value::Null))) && is_true(&(!is_equal(&code, &Value::Str("0".to_string())))));
        if is_true(&error) || is_true(&(!is_equal(&message, &Value::Null))) {
            let mut feedback: Value = add(&add(&self.id, &Value::Str(" ".to_string())), &body);
            self.throw_exactly_matched_exception(get_value(&self.exceptions, &Value::Str("exact".to_string())), code.clone(), feedback.clone());
            self.throw_exactly_matched_exception(get_value(&self.exceptions, &Value::Str("exact".to_string())), message.clone(), feedback.clone());
            self.throw_broadly_matched_exception(get_value(&self.exceptions, &Value::Str("broad".to_string())), message.clone(), feedback.clone());
            panic!("{}", crate::exchange_errors::exchange_error(feedback));
        }
        return Value::Null;

    Value::Null
}
